import {
  Table,
  TableCaption,
  TableHeader,
  TableRow,
  TableHead,
  TableBody,
  TableCell
} from '@/components/ui/table';
import { Experience } from '@/types/Experience';
import dateFormater from '@/utils/dateFormater';
import AccordionButtons from '../AccordionItems/AccordionButtons';
import Accordion from '@/components/Accordion';
import DeleteButton from '../DeleteButton';
import Form from '@/components/Form';
import Input from '@/app/(private)/login/components/Input';
import Label from '@/app/(private)/login/components/Label';
import { createExperience } from '../../actions';

// TODO: refatorar o fetch das experiências e o componente

export default async function ExperiencesTable() {
  const response = await fetch(`${process.env.API_URL}/experiences`);
  const data = await response.json();
  const { data: experiences } = data;
  console.log('Experiências:', experiences);
  return (
    <>
      <Table className="w-full pb-10 text-gray lg:justify-self-center lg:text-lg 2xl:w-8/10 dark:text-white">
        <TableCaption className="pb-10 lg:text-lg">
          Lista de experiências
        </TableCaption>
        <TableHeader>
          <TableRow className="*:text-center lg:*:text-start">
            <TableHead className="w-[50px]">Nome</TableHead>
            <TableHead>Descrição</TableHead>
            <TableHead>Início</TableHead>
            <TableHead>Fim</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {experiences &&
            experiences.map((experience: Experience) => (
              <TableRow
                key={experience.id}
                className="*:text-center lg:*:text-start"
              >
                <TableCell className="w-[100px] lg:w-[200px]">
                  <h3 className="text-sm font-semibold text-wrap text-gray lg:text-lg dark:text-white">
                    {experience.title}
                  </h3>
                </TableCell>
                <TableCell className="max-w-[100px]">
                  <p className="text-small text-wrap">
                    {experience.description}
                  </p>
                </TableCell>
                <TableCell className="max-w-[100px]">
                  <p className="text-wrap">
                    {dateFormater(experience.startedAt)}
                  </p>
                </TableCell>
                <TableCell className="max-w-[100px]">
                  <p className="text-wrap">
                    {dateFormater(experience.finishedAt)}
                  </p>
                </TableCell>
                <TableCell>
                  <DeleteButton
                    endpoint="experiences"
                    identifier={experience.id}
                  />
                </TableCell>
              </TableRow>
            ))}
        </TableBody>
      </Table>
      <Accordion>
        <Form action={createExperience}>
          <Label htmlFor="title">Título:</Label>
          <Input name="title" id="title" />
          <Label htmlFor="description">Descrição:</Label>
          <textarea
            rows={4}
            name="description"
            id="description"
            className="focus:border-blue focus:ring-blue w-full rounded-md border border-gray/10 bg-white/10 px-4 py-3 font-roboto-flex text-gray transition placeholder:text-gray/50 focus:ring-1 focus:outline-none dark:border-white/10 dark:bg-black/10 dark:text-white dark:placeholder:text-white/50"
          />
          <Label htmlFor="startedAt">Data do começo:</Label>
          <Input name="startedAt" id="startedAt" type="date" />
          <Label htmlFor="finishedAt">Data do fim:</Label>
          <Input name="finishedAt" id="finishedAt" type="date" />
        </Form>
      </Accordion>
    </>
  );
}
